import React, { useState, useContext } from 'react';
import { taxasIRT } from '../data/mockData';
import { AppContext } from '../App';
import { Colaborador } from '../types';

const Processamento: React.FC = () => {
  const { empresa, colaboradores, setMessage } = useContext(AppContext);
  const ativos = colaboradores.filter(c => c.status === 'Ativo');

  const currentYear = new Date().getFullYear();
  const currentDay = new Date().getDate();
  const [selectedMonth, setSelectedMonth] = useState('Janeiro');
  const [selectedYear, setSelectedYear] = useState(currentYear.toString());
  const [selectedDay, setSelectedDay] = useState(currentDay.toString());

  const [showFormModal, setShowFormModal] = useState(false);
  const [showReceiptModal, setShowReceiptModal] = useState(false);
  const [selectedColab, setSelectedColab] = useState<Colaborador | null>(null);

  // Form states
  const [formSalario, setFormSalario] = useState(0);
  const [formFaltas, setFormFaltas] = useState(0);
  const [formAlimentacao, setFormAlimentacao] = useState(0);
  const [formTransporte, setFormTransporte] = useState(0);
  const [formFerias, setFormFerias] = useState(0);
  const [outrosSubsidios, setOutrosSubsidios] = useState<{nome: string, valor: number}[]>([]);
  const [formHorasExtra, setFormHorasExtra] = useState(0);
  const [formBonus, setFormBonus] = useState(0);

  const calcularIRT = (baseSujeitaIRT: number) => {
    const escalao = taxasIRT.find(t => baseSujeitaIRT >= t.minimo && baseSujeitaIRT <= t.maximo);
    if (!escalao) return 0;
    const calc = ((baseSujeitaIRT - escalao.minimo) * (escalao.taxa / 100)) + escalao.parcelaAbt;
    return calc > 0 ? calc : 0;
  };

  const handleStartProcessar = (colab: Colaborador) => {
    setSelectedColab(colab);
    setFormSalario(colab.salarioBase || 0);
    setFormFaltas(0);
    setFormAlimentacao(30000);
    setFormTransporte(20000);
    setFormFerias(0);
    setOutrosSubsidios([]);
    setFormHorasExtra(0);
    setFormBonus(0);
    setShowFormModal(true);
  };

  const handleAddSubsidio = (e: React.ChangeEvent<HTMLSelectElement>) => {
    const value = e.target.value;
    if (value === 'Outro') {
      const nome = prompt('Digite o nome do subsídio:');
      if (nome) {
        setOutrosSubsidios([...outrosSubsidios, { nome: nome.trim(), valor: 0 }]);
      }
    } else if (value !== '') {
      setOutrosSubsidios([...outrosSubsidios, { nome: value, valor: 0 }]);
    }
    e.target.value = ''; // Reset select
  };

  const handleUpdateSubsidioValor = (index: number, valor: number) => {
    const newSubsidios = [...outrosSubsidios];
    newSubsidios[index].valor = valor;
    setOutrosSubsidios(newSubsidios);
  };

  const removeOutroSubsidio = (index: number) => {
    setOutrosSubsidios(outrosSubsidios.filter((_, i) => i !== index));
  };

  const handleConfirmForm = (e: React.FormEvent) => {
    e.preventDefault();
    setShowFormModal(false);
    setShowReceiptModal(true);
    setMessage({
      title: 'Processamento Concluído',
      text: `O salário de ${selectedColab?.nome} foi calculado com sucesso.`,
      type: 'success'
    });
  };

  const currentCalc = () => {
    const totalOutros = outrosSubsidios.reduce((acc, curr) => acc + curr.valor, 0);
    const totalBruto = formSalario + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus;
    const baseSalarioLiquidoFaltas = formSalario - formFaltas;

    const taxaINSS = empresa?.taxaINSS || 3;
    const valorINSS = baseSalarioLiquidoFaltas * (taxaINSS / 100);
    const baseIRT = baseSalarioLiquidoFaltas - valorINSS + formAlimentacao + formTransporte + formFerias + totalOutros + formHorasExtra + formBonus; 
    const valorIRT = calcularIRT(baseIRT);

    const totalDescontos = valorINSS + valorIRT + formFaltas;
    const salarioLiquido = totalBruto - totalDescontos;

    return { totalBruto, valorINSS, valorIRT, totalDescontos, salarioLiquido };
  };

  const handleImprimir = () => {
    window.print();
  };

  const handleGuardar = () => {
    const element = document.getElementById('recibo-para-impressao');
    if (!element) return;

    // @ts-ignore
    const opt = {
      margin: 0,
      filename: `Recibo_${selectedColab?.nome.replace(/ /g, '_')}_${selectedMonth}.pdf`,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, logging: false },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' }
    };

    // @ts-ignore
    window.html2pdf().from(element).set(opt).save();
  };

  return (
    <div className="p-8">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black tracking-tight">Processamento de Salários</h2>
          <p className="text-slate-500 text-sm">Gere a folha de pagamento do período selecionado.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6 mb-8">
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">Mês de Ref.</label>
          <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 font-black text-slate-800 dark:text-white text-sm">
            {['Janeiro', 'Fevereiro', 'Março', 'Abril', 'Maio', 'Junho', 'Julho', 'Agosto', 'Setembro', 'Outubro', 'Novembro', 'Dezembro'].map(m => (
              <option key={m} value={m}>{m}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">Ano</label>
          <select value={selectedYear} onChange={e => setSelectedYear(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 font-black text-slate-800 dark:text-white text-sm">
            {['2024', '2025', '2026', '2027'].map(y => (
              <option key={y} value={y}>{y}</option>
            ))}
          </select>
        </div>
        <div className="bg-white dark:bg-slate-900 p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
          <label className="block text-[10px] font-black text-slate-400 uppercase mb-1 tracking-widest">Dia</label>
          <input type="number" min="1" max="31" value={selectedDay} onChange={e => setSelectedDay(e.target.value)} className="w-full bg-transparent border-none p-0 focus:ring-0 font-black text-slate-800 dark:text-white text-sm" />
        </div>
        <div className="bg-primary/5 p-4 rounded-xl border border-primary/10 flex items-center justify-between">
          <div>
            <p className="text-[10px] font-black text-primary/60 uppercase tracking-widest">Gestão</p>
            <p className="text-xs font-black text-primary uppercase">Manual</p>
          </div>
          <span className="material-symbols-outlined text-primary/40">event_note</span>
        </div>
      </div>

      <div className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-200 dark:border-slate-800 overflow-hidden shadow-sm">
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800">
                <th className="p-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Colaborador</th>
                <th className="p-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Salário Base</th>
                <th className="p-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Ação</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {ativos.map(c => (
                <tr key={c.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/20 transition-colors">
                  <td className="p-5">
                    <div className="flex items-center gap-4">
                      <div className="size-11 rounded-full bg-primary/10 flex items-center justify-center text-primary font-black text-xs uppercase border-2 border-primary/5">{c.nome.substring(0, 2)}</div>
                      <div>
                        <p className="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight">{c.nome}</p>
                        <p className="text-[10px] font-bold text-slate-400 uppercase">{c.cargo}</p>
                      </div>
                    </div>
                  </td>
                  <td className="p-5 text-right font-black text-slate-900 dark:text-white text-sm">{c.salarioBase.toLocaleString()} Kz</td>
                  <td className="p-5 text-center">
                    <button onClick={() => handleStartProcessar(c)} className="bg-primary hover:bg-primary/90 text-white px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-lg shadow-primary/20 transition-all active:scale-95">Processar</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showFormModal && selectedColab && (
        <div className="fixed inset-0 bg-slate-900/60 flex items-center justify-center z-[90] p-4 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-3xl max-w-lg w-full max-h-[90vh] overflow-y-auto shadow-2xl animate-in zoom-in-95 duration-200">
            <div className="p-8 border-b border-slate-100 dark:border-slate-800 flex items-start justify-between">
              <div>
                <h2 className="font-black text-xl text-slate-900 dark:text-white uppercase tracking-tighter">Cálculo de Salário</h2>
                <div className="text-primary text-[10px] font-black uppercase tracking-widest mt-1">{selectedColab.nome}</div>
              </div>
              <button onClick={() => setShowFormModal(false)} className="p-2 hover:bg-slate-50 dark:hover:bg-slate-800 rounded-xl transition-colors"><span className="material-symbols-outlined text-slate-400">close</span></button>
            </div>
            <form onSubmit={handleConfirmForm} className="p-8 space-y-6">
              <div className="space-y-1.5">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Salário Base de Acordo ao Contrato (Kz)</label>
                <input required type="text" value={formSalario ? formSalario.toLocaleString('pt-AO') : ''} onChange={e => setFormSalario(Number(e.target.value.replace(/\D/g, '')))} className="w-full px-5 py-3.5 bg-slate-50 dark:bg-slate-800 border-2 border-slate-100 dark:border-slate-800 rounded-2xl font-black text-primary text-2xl focus:border-primary outline-none transition-all" />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Alimentação</label><input type="number" value={formAlimentacao === 0 ? '' : formAlimentacao} onChange={e => setFormAlimentacao(Number(e.target.value))} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-xl font-bold text-sm" /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Transporte</label><input type="number" value={formTransporte === 0 ? '' : formTransporte} onChange={e => setFormTransporte(Number(e.target.value))} className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-xl font-bold text-sm" /></div>
              </div>

              {/* Dynamic Subsidies Grid */}
              <div className="space-y-4 pt-2">
                <div className="flex items-center justify-between border-b-2 border-slate-50 pb-2">
                   <label className="text-[11px] font-black text-primary uppercase tracking-tighter flex items-center gap-2">
                     <span className="material-symbols-outlined text-base">add_box</span>
                     Outros Subsídios
                   </label>
                   <select 
                     onChange={handleAddSubsidio}
                     className="text-[10px] bg-slate-100 dark:bg-slate-800 border-none rounded-lg py-1 px-3 font-black text-slate-500 uppercase tracking-widest cursor-pointer hover:bg-primary hover:text-white transition-colors outline-none"
                   >
                     <option value="">+ Adicionar</option>
                     <option value="Subsídio de Chefia">Subsídio de Chefia</option>
                     <option value="Subsídio de Disponibilidade">Disponibilidade</option>
                     <option value="Gratificação">Gratificação</option>
                     <option value="Outro">Outro...</option>
                   </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  {outrosSubsidios.map((s, idx) => (
                    <div key={idx} className="space-y-1.5 group animate-in fade-in slide-in-from-top-2">
                       <div className="flex justify-between items-center pr-1">
                          <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest truncate max-w-[120px]">{s.nome}</label>
                          <button type="button" onClick={() => removeOutroSubsidio(idx)} className="text-red-400 hover:text-red-600 transition-colors"><span className="material-symbols-outlined text-xs">close</span></button>
                       </div>
                       <input 
                         type="number" 
                         value={s.valor === 0 ? '' : s.valor} 
                         onChange={e => handleUpdateSubsidioValor(idx, Number(e.target.value))} 
                         className="w-full px-4 py-3 bg-slate-50 dark:bg-slate-800 border border-slate-100 dark:border-slate-800 rounded-xl font-bold text-sm text-slate-900 dark:text-white" 
                       />
                    </div>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4 border-t-2 border-slate-50 pt-4">
                <div className="space-y-1.5"><label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Horas Extra</label><input type="number" value={formHorasExtra === 0 ? '' : formHorasExtra} onChange={e => setFormHorasExtra(Number(e.target.value))} className="w-full px-4 py-3 bg-emerald-50/20 border border-emerald-100 rounded-xl font-bold text-sm" /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-emerald-600 uppercase tracking-widest">Bónus/Prémio</label><input type="number" value={formBonus === 0 ? '' : formBonus} onChange={e => setFormBonus(Number(e.target.value))} className="w-full px-4 py-3 bg-emerald-50/20 border border-emerald-100 rounded-xl font-bold text-sm" /></div>
              </div>

              <div className="space-y-1.5 border-t-2 border-slate-50 pt-4">
                <label className="text-[10px] font-black text-red-500 uppercase tracking-widest">Faltas e Descontos</label>
                <input type="number" value={formFaltas === 0 ? '' : formFaltas} onChange={e => setFormFaltas(Number(e.target.value))} className="w-full px-5 py-3.5 bg-red-50/30 border-2 border-red-50 rounded-2xl font-black text-red-600" />
              </div>

              <button type="submit" className="w-full mt-4 py-4 bg-primary text-white rounded-2xl font-black hover:bg-primary/90 flex items-center justify-center gap-3 shadow-2xl shadow-primary/20 transition-all uppercase tracking-[3px] text-xs">
                Confirmar e Gerar Recibo
              </button>
            </form>
          </div>
        </div>
      )}

      {showReceiptModal && selectedColab && (
        <div className="fixed inset-0 bg-slate-900/80 flex items-center justify-center z-[100] p-4 backdrop-blur-md">
          <div className="bg-white rounded-3xl max-w-[210mm] w-full max-h-[95vh] overflow-y-auto shadow-[0_0_100px_rgba(0,0,0,0.3)] relative">
            <style>{`
              @media print {
                @page { size: A4; margin: 0; }
                body * { visibility: hidden; }
                #recibo-para-impressao, #recibo-para-impressao * { visibility: visible; }
                #recibo-para-impressao { 
                  position: absolute; 
                  left: 0; 
                  top: 0; 
                  width: 210mm;
                  min-height: 297mm;
                  margin: 0;
                  padding: 20mm;
                  box-sizing: border-box;
                  background: white;
                }
                .no-print { display: none !important; }
              }
            `}</style>

            <div className="p-16 bg-white text-slate-900" id="recibo-para-impressao" style={{ minHeight: '297mm', boxSizing: 'border-box', display: 'flex', flexDirection: 'column' }}>
              {/* Header */}
              <div className="flex justify-between items-start border-b-4 border-slate-900 pb-8 mb-10">
                <div>
                  <h1 className="text-3xl font-black text-slate-900 uppercase tracking-tighter leading-none">{empresa?.nome || 'EMPRESA'}</h1>
                  <p className="text-xs font-black text-slate-500 mt-2 uppercase tracking-widest">NIF: {empresa?.nif || '-'}</p>
                  <p className="text-[10px] text-slate-400 max-w-[350px] leading-tight mt-2 font-medium">{empresa?.endereco || ''}</p>
                </div>
                <div className="text-right">
                  <h2 className="text-lg font-black text-white bg-slate-900 px-6 py-2 rounded-sm inline-block uppercase tracking-[4px]">Recibo</h2>
                  <div className="mt-4 text-right">
                    <p className="text-xs font-black uppercase tracking-widest">Período: {selectedMonth} / {selectedYear}</p>
                    <p className="text-[9px] font-bold text-slate-400 uppercase mt-1">Série: {selectedYear}/{selectedMonth.substring(0,3).toUpperCase()}</p>
                  </div>
                </div>
              </div>

              {/* Info Grid */}
              <div className="grid grid-cols-2 gap-10 mb-10">
                <div className="border-l-4 border-slate-200 pl-6 py-2">
                  <h3 className="text-[10px] font-black text-slate-300 mb-2 uppercase tracking-widest">Beneficiário</h3>
                  <p className="text-lg font-black uppercase tracking-tight">{selectedColab.nome}</p>
                  <div className="grid grid-cols-2 gap-4 mt-4">
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase">ID Interno</p>
                      <p className="text-xs font-black">{selectedColab.numeroColaborador || '-'}</p>
                    </div>
                    <div>
                      <p className="text-[9px] font-bold text-slate-400 uppercase">Cargo/Função</p>
                      <p className="text-xs font-black">{selectedColab.cargo}</p>
                    </div>
                  </div>
                </div>
                <div className="border-l-4 border-primary pl-6 py-2 bg-slate-50/50 rounded-r-lg">
                  <h3 className="text-[10px] font-black text-primary/40 mb-2 uppercase tracking-widest">Dados de Pagamento</h3>
                  <div className="grid grid-cols-1 gap-2">
                    <p className="text-[10px] font-bold text-slate-600">NIF: <span className="text-slate-900">{selectedColab.nif}</span></p>
                    <p className="text-[10px] font-bold text-slate-600">INSS: <span className="text-slate-900">{selectedColab.inss || '-'}</span></p>
                    <div className="mt-2 text-primary">
                       <p className="text-[9px] font-black uppercase tracking-widest">IBAN para Depósito</p>
                       <p className="text-base font-black tracking-tight">{selectedColab.iban || '-'}</p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Table */}
              <div className="flex-1">
                <table className="w-full text-xs border-collapse">
                  <thead>
                    <tr className="bg-slate-100 text-slate-900 font-black text-[10px] uppercase tracking-[2px]">
                      <th className="p-4 text-left border-b-2 border-slate-900">Descrição Detalhada</th>
                      <th className="p-4 text-right border-b-2 border-slate-900 w-40">Total (Kz)</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-slate-100 font-black text-sm"><td className="p-4">Salário Base Mensal</td><td className="p-4 text-right">{formSalario.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                    {formAlimentacao > 0 && <tr className="border-b border-slate-100"><td className="p-4">Subsídio de Alimentação</td><td className="p-4 text-right">{formAlimentacao.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                    {formTransporte > 0 && <tr className="border-b border-slate-100"><td className="p-4">Subsídio de Transporte</td><td className="p-4 text-right">{formTransporte.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                    {outrosSubsidios.map((s, idx) => (
                      <tr key={idx} className="border-b border-slate-100"><td className="p-4">{s.nome}</td><td className="p-4 text-right">{s.valor.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                    ))}
                    {formHorasExtra > 0 && <tr className="border-b border-slate-100"><td className="p-4">Remuneração por Horas Extra</td><td className="p-4 text-right">{formHorasExtra.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                    {formBonus > 0 && <tr className="border-b border-slate-100"><td className="p-4">Bónus e Premiações Especial</td><td className="p-4 text-right">{formBonus.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}

                    <tr className="bg-slate-50 font-black text-slate-900 uppercase text-[10px]"><td className="p-4 text-right">Rendimentos Ilíquidos (Total Bruto)</td><td className="p-4 text-right text-base">{currentCalc().totalBruto.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>

                    <tr className="bg-white"><td colSpan={2} className="px-4 py-6 text-[10px] font-black text-slate-300 uppercase tracking-[4px]">Deduções Legais</td></tr>

                    <tr className="border-b border-slate-50 text-slate-500"><td className="p-4 italic">Contribuição para Segurança Social ({empresa?.taxaINSS || 3}%)</td><td className="p-4 text-right">- {currentCalc().valorINSS.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                    <tr className="border-b border-slate-50 text-slate-500"><td className="p-4 italic">Imposto sobre o Rendimento do Trabalho (IRT)</td><td className="p-4 text-right">- {currentCalc().valorIRT.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>
                    {formFaltas > 0 && <tr className="border-b border-slate-50 text-red-500"><td className="p-4 italic font-bold">Desconto por Ausências / Faltas</td><td className="p-4 text-right font-bold">- {formFaltas.toLocaleString('pt-AO', { minimumFractionDigits: 2 })}</td></tr>}
                  </tbody>
                </table>
              </div>

              {/* Total Box */}
              <div className="flex justify-start mt-10 mb-20">
                <div className="bg-slate-900 text-white p-8 rounded-2xl w-full max-w-[450px] flex justify-between items-center shadow-2xl">
                  <div>
                    <p className="text-[10px] font-black uppercase tracking-[3px] text-slate-400 mb-1">Total a Liquidar</p>
                    <p className="text-3xl font-black">{currentCalc().salarioLiquido.toLocaleString('pt-AO', { minimumFractionDigits: 2 })} Kz</p>
                  </div>
                  <div className="size-16 rounded-full border-4 border-white/10 flex items-center justify-center">
                    <span className="material-symbols-outlined text-4xl">payments</span>
                  </div>
                </div>
              </div>

              {/* Footer */}
              <div className="mt-auto pt-10 border-t-2 border-slate-100 text-center">
                <div className="flex justify-between items-center text-[9px] font-black text-slate-400 uppercase tracking-widest">
                  <p>Software certificado SALYA v2.0</p>
                  <p>Documento processado por meios informáticos</p>
                  <p>Data: {new Date().toLocaleDateString()}</p>
                </div>
              </div>
            </div>

            <div className="p-8 bg-slate-50 border-t flex gap-4 no-print sticky bottom-0 rounded-b-3xl z-10">
              <button onClick={handleGuardar} className="flex-1 py-4 bg-primary text-white rounded-2xl font-black flex items-center justify-center gap-3 shadow-2xl shadow-primary/20 transition-all uppercase tracking-widest text-xs active:scale-95"><span className="material-symbols-outlined">description</span> Exportar PDF</button>
              <button onClick={handleImprimir} className="flex-1 py-4 bg-white text-slate-900 border-2 border-slate-200 rounded-2xl font-black flex items-center justify-center gap-3 hover:bg-slate-100 transition-all uppercase tracking-widest text-xs active:scale-95"><span className="material-symbols-outlined">print</span> Imprimir Recibo</button>
              <button onClick={() => setShowReceiptModal(false)} className="px-10 py-4 bg-slate-200 text-slate-600 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-slate-300 transition-colors">Fechar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Processamento;
